function UIBoxLottery:updateLanguage()
    self:getChildWindow("BoxLottery-Title-Text", GUIType.StaticText):SetText(Lang:getString("gui.chest.lottery.title"))
    self:getChildWindow("BoxLottery-Open-Hint-Text", GUIType.StaticText):SetText(Lang:getString("gui.chest.lottery.hint"))

end

function UIBoxLottery:setLotteryConfig()
    if self.needIntegral == 0 then
        self.layIntegral:SetVisible(false)
        return
    end
    if self.Lv1Num > 0 then
        self.actLv1Box:PlaySkill("active")
    else
        self.actLv1Box:PlaySkill("idle")
    end
    if self.Lv1Num <= 0 then
        self.btnOpenBox:SetNormalImage("set:dress.json image:btn_orange")
        self.btnOpenBox:SetPushedImage("set:dress.json image:btn_orange")
        self.siKeyIcon:SetVisible(true)
        self.stOneOpenText:SetText(self.Lv1Box.NeedKey)
        self.stOneOpenText:SetXPosition({ 0.5, 0 })
    else
        self.btnOpenBox:SetNormalImage("set:dress.json image:btn_green")
        self.btnOpenBox:SetPushedImage("set:dress.json image:btn_green")
        self.siKeyIcon:SetVisible(false)
        self.stOneOpenText:SetText(string.format("%s(%d)", Lang:getString("bed.war.free.box.lottery"), self.Lv1Num))
        self.stOneOpenText:SetXPosition({ 0, 0 })
    end

    if self.Lv1Num <= 10 then
        self.btnOpenBoxTen:SetNormalImage("set:dress.json image:btn_orange")
        self.btnOpenBoxTen:SetPushedImage("set:dress.json image:btn_orange")
        self.siKeyIconTen:SetVisible(true)
        self.stTenOpenText:SetText(self.Lv1Box.NeedKey * 10)
        self.stTenOpenText:SetXPosition({ 0.5, 0 })
    else
        self.btnOpenBoxTen:SetNormalImage("set:dress.json image:btn_green")
        self.btnOpenBoxTen:SetPushedImage("set:dress.json image:btn_green")
        self.siKeyIconTen:SetVisible(false)
        self.stTenOpenText:SetText(string.format("%s(%d)", Lang:getString("bed.war.free.box.lottery"), math.floor(self.Lv1Num / 10)))
        self.stTenOpenText:SetXPosition({ 0, 0 })
    end

    self.layIntegral:SetVisible(true)
    self.pgIntegralProgress:SetProgress(self.curIntegral / self.needIntegral)
    if self.IntegralBox ~= nil then
        if self.IntegralNum > 0 then
            self.stProgressText:SetText(string.format("%d/%d(%d)", self.curIntegral, self.needIntegral, self.IntegralNum))
            self.actIntegralActor:PlaySkill("active")
        else
            self.stProgressText:SetText(string.format("%d/%d", self.curIntegral, self.needIntegral))
            if self.curIntegral / self.needIntegral >= 1 then
                self.actIntegralActor:PlaySkill("active")
            else
                self.actIntegralActor:PlaySkill("idle")
            end
        end
    else
        self.stProgressText:SetText(string.format("%d/%d", self.curIntegral, self.needIntegral))
        self.actIntegralActor:PlaySkill("idle")
    end
end

return UIBoxLottery